#!/usr/bin/env node
/**
 * Material Map Generator 0.3.12-preview -- Single-File Local Server
 * Run: node mapgen_v0.3.12-preview.js
 * Platform: Windows / macOS / Linux / Android (Termux)
 *
 * This is a self-contained single-file release.
 * All assets (HTML, CSS, shaders, JS) are embedded as base64.
 */

const http = require('http');
const execSync = require('child_process').execSync;
const os = require('os');
const zlib = require('zlib');

const PORT = parseInt(process.env.MAPGEN_PORT, 10) || 8765;
const HOST = process.env.MAPGEN_HOST || '127.0.0.1';
const SELF = __filename;

/* ── embedded HTML (base64) ── */
var _src = require('fs').readFileSync(SELF, 'utf8');
var _marker = '==HTML_DATA_START==';
var _pos = _src.lastIndexOf(_marker);
if (_pos < 0) { console.error('Corrupted: missing HTML data'); process.exit(1); }
var _b64block = _src.substring(_pos + _marker.length);
_b64block = _b64block.replace(/^\s*\/\*\s*/, '').replace(/\s*\*\/\s*$/, '');
_b64block = _b64block.replace(/\s/g, '');
var serverHTML = Buffer.from(_b64block, 'base64').toString('utf8');

/* Pre-compress for gzip */
var serverHTML_gz = null;
zlib.gzip(serverHTML, function(err, buf) { if (!err) serverHTML_gz = buf; });

/* HTTP server */
var server = http.createServer(function(req, res) {
    if (req.url === '/health') {
        res.writeHead(200, { 'Content-Type': 'application/json' });
        res.end('{"status":"ok","version":"0.3.12-preview","arch":"single-file"}');
        return;
    }
    var headers = {
        'Content-Type': 'text/html; charset=utf-8',
        'Cache-Control': 'no-cache',
        'Access-Control-Allow-Origin': '*',
        'X-Content-Type-Options': 'nosniff'
    };
    var acceptGzip = (req.headers['accept-encoding'] || '').indexOf('gzip') >= 0;
    if (acceptGzip && serverHTML_gz) {
        headers['Content-Encoding'] = 'gzip';
        res.writeHead(200, headers);
        res.end(serverHTML_gz);
    } else {
        res.writeHead(200, headers);
        res.end(serverHTML);
    }
});

function openBrowser(url) {
    var p = os.platform();
    try {
        if (p === 'darwin') { execSync("open '" + url + "'", { timeout: 3000, stdio: 'ignore' }); }
        else if (p === 'win32') { execSync('start "" "' + url + '"', { timeout: 3000, stdio: 'ignore', shell: true }); }
        else {
            try { execSync('which termux-open', { stdio: 'pipe' }); execSync("termux-open '" + url + "'", { timeout: 3000, stdio: 'ignore' }); }
            catch(e) { execSync("xdg-open '" + url + "'", { timeout: 3000, stdio: 'ignore' }); }
        }
        console.log('  Browser opened');
    } catch(e) { console.log('  Open manually: ' + url); }
}

server.listen(PORT, HOST, function() {
    var url = 'http://' + HOST + ':' + PORT;
    console.log('');
    console.log('  +---------------------------------------------+');
    console.log('  |  Material Map Generator  0.3.12-preview            |');
    console.log('  +---------------------------------------------+');
    console.log('');
    console.log('  Single-file release (all assets embedded)');
    console.log('  ' + url);
    console.log('  Ctrl+C to stop');
    console.log('');
    setTimeout(function() { openBrowser(url); }, 500);
});

server.on('error', function(err) {
    if (err.code === 'EADDRINUSE') {
        console.error('Port ' + PORT + ' in use. Try: MAPGEN_PORT=8766 node mapgen_v0.3.12-preview.js');
    } else { console.error('Error: ' + err.message); }
    process.exit(1);
});

process.on('SIGINT', function() {
    console.log('\nStopped.');
    server.close(function() { process.exit(0); });
});

/* data marker */
//==HTML_DATA_START==
